import React, { useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import {
  Card,
  CardMedia,
  CardContent,
  Typography,
  Box,
  Button,
  Rating,
  Chip,
  IconButton,
  CircularProgress,
  Tooltip,
  Fade,
  Backdrop,
} from '@mui/material';
import {
  Star,
  StarBorder,
  Close,
  PlayArrow,
  Favorite,
  Share,
  BookmarkBorder,
  TrendingUp,
  Group,
  Psychology,
  EmojiEvents,
} from '@mui/icons-material';

// Mock AuthContext for demo
const AuthContext = React.createContext({
  isAuthenticated: true,
});

// Mock services
const rateMovie = async (data) => {
  return new Promise(resolve => {
    setTimeout(() => resolve({ rating: data.rating }), 500);
  });
};

const checkUserRating = async (movieId) => {
  return new Promise(resolve => {
    setTimeout(() => resolve({ has_rated: false }), 300);
  });
};

const MovieCard = ({ 
  movie = {
    id: 1,
    title: "Inception",
    year: 2010,
    poster_url: "https://images.unsplash.com/photo-1489599735734-79b4ba5c18a6?w=300&h=450&fit=crop",
    avg_rating: 4.5,
    rating_count: 1247,
    plot: "A thief who enters the dreams of others to steal their secrets from their subconscious gets a chance to have his criminal record erased in exchange for one final job.",
    genres: ["Action", "Sci-Fi", "Thriller", "Drama"],
    recommendation_score: 0.85
  }, 
  showRecommendationScore = true, 
  recommendationSources = ['collaborative', 'content'], 
  onRatingUpdate = null 
}) => {
  const { isAuthenticated } = useContext(AuthContext);
  const [showQuickRate, setShowQuickRate] = useState(false);
  const [quickRating, setQuickRating] = useState(0);
  const [hoverRating, setHoverRating] = useState(0);
  const [isRating, setIsRating] = useState(false);
  const [userRating, setUserRating] = useState(null);
  const [isHovered, setIsHovered] = useState(false);
  const [isFavorited, setIsFavorited] = useState(false);

  React.useEffect(() => {
    if (isAuthenticated && movie.id) {
      fetchUserRating();
    }
  }, [isAuthenticated, movie.id]);

  const fetchUserRating = async () => {
    try {
      const ratingData = await checkUserRating(movie.id);
      if (ratingData.has_rated) {
        setUserRating(ratingData.rating);
      }
    } catch (error) {
      // User hasn't rated this movie, which is fine
    }
  };

  const handleQuickRate = async (rating) => {
    if (!isAuthenticated) return;

    setIsRating(true);
    try {
      const ratingData = await rateMovie({
        movie_id: movie.id,
        rating: rating,
        review: ''
      });

      setUserRating(ratingData.rating);
      setShowQuickRate(false);

      if (onRatingUpdate) {
        onRatingUpdate(movie.id, rating);
      }
    } catch (error) {
      console.error('Error rating movie:', error);
    } finally {
      setIsRating(false);
    }
  };

  const getRecommendationBadge = () => {
    if (!showRecommendationScore || !recommendationSources || recommendationSources.length === 0) {
      return null;
    }

    const isCollaborative = recommendationSources.includes('collaborative');
    const isContent = recommendationSources.includes('content');
    const isBoth = isCollaborative && isContent;

    const badgeConfig = isBoth
      ? { text: 'Perfect Match', icon: <EmojiEvents sx={{ fontSize: 14 }} />, color: '#4ade80' }
      : isCollaborative
        ? { text: 'Similar Users', icon: <Group sx={{ fontSize: 14 }} />, color: '#3b82f6' }
        : { text: 'Your Taste', icon: <Psychology sx={{ fontSize: 14 }} />, color: '#f59e0b' };

    return (
      <Chip
        icon={badgeConfig.icon}
        label={badgeConfig.text}
        size="small"
        sx={{
          position: 'absolute',
          top: 12,
          right: 12,
          zIndex: 3,
          background: `linear-gradient(135deg, ${badgeConfig.color}dd, ${badgeConfig.color}ff)`,
          color: 'white',
          backdropFilter: 'blur(8px)',
          border: `1px solid ${badgeConfig.color}44`,
          fontWeight: 600,
          fontSize: '0.7rem',
          height: 24,
          '& .MuiChip-icon': {
            color: 'white',
          },
        }}
      />
    );
  };

  const formatYear = (year) => {
    return year ? `(${year})` : '';
  };

  const truncateTitle = (title, maxLength = 30) => {
    if (!title) return '';
    return title.length > maxLength ? `${title.substring(0, maxLength)}...` : title;
  };

  return (
    <Card
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      sx={{
        position: 'relative',
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        background: 'rgba(255, 255, 255, 0.1)',
        backdropFilter: 'blur(20px)',
        border: '1px solid rgba(255, 255, 255, 0.2)',
        borderRadius: '1rem',
        overflow: 'hidden',
        transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
        transform: isHovered ? 'translateY(-8px) scale(1.02)' : 'translateY(0) scale(1)',
        boxShadow: isHovered 
          ? '0 25px 50px rgba(0, 0, 0, 0.3), 0 0 30px rgba(168, 85, 247, 0.2)' 
          : '0 8px 25px rgba(0, 0, 0, 0.15)',
        '&::before': {
          content: '""',
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: isHovered 
            ? 'linear-gradient(135deg, rgba(168, 85, 247, 0.1) 0%, rgba(236, 72, 153, 0.1) 100%)'
            : 'transparent',
          transition: 'background 0.3s ease',
          zIndex: 1,
          pointerEvents: 'none',
        }
      }}
    >
      {getRecommendationBadge()}

      {/* Movie Poster */}
      <Box sx={{ position: 'relative', aspectRatio: '2/3' }}>
        <CardMedia
          component="img"
          image={movie.poster_url || 'https://images.unsplash.com/photo-1489599735734-79b4ba5c18a6?w=300&h=450&fit=crop'}
          alt={movie.title}
          onError={(e) => {
            e.target.src = 'https://images.unsplash.com/photo-1489599735734-79b4ba5c18a6?w=300&h=450&fit=crop';
          }}
          sx={{
            height: '100%',
            width: '100%',
            objectFit: 'cover',
            transition: 'transform 0.3s ease',
            transform: isHovered ? 'scale(1.05)' : 'scale(1)',
          }}
        />

        {/* Overlay with hover effects */}
        <Fade in={isHovered} timeout={300}>
          <Box
            sx={{
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              background: 'linear-gradient(to bottom, transparent 0%, rgba(0, 0, 0, 0.8) 100%)',
              display: 'flex',
              flexDirection: 'column',
              justifyContent: 'space-between',
              padding: 2,
              zIndex: 2,
            }}
          >
            {/* Top actions */}
            <Box sx={{ display: 'flex', gap: 1, justifyContent: 'flex-end' }}>
              <Tooltip title="Add to favorites">
                <IconButton
                  size="small"
                  onClick={(e) => {
                    e.stopPropagation();
                    setIsFavorited(!isFavorited);
                  }}
                  sx={{
                    background: 'rgba(255, 255, 255, 0.2)',
                    backdropFilter: 'blur(8px)',
                    color: isFavorited ? '#ef4444' : 'white',
                    transition: 'all 0.2s ease',
                    '&:hover': {
                      background: 'rgba(255, 255, 255, 0.3)',
                      transform: 'scale(1.1)',
                    },
                  }}
                >
                  <Favorite sx={{ fontSize: 18 }} />
                </IconButton>
              </Tooltip>
              <Tooltip title="Share">
                <IconButton
                  size="small"
                  sx={{
                    background: 'rgba(255, 255, 255, 0.2)',
                    backdropFilter: 'blur(8px)',
                    color: 'white',
                    transition: 'all 0.2s ease',
                    '&:hover': {
                      background: 'rgba(255, 255, 255, 0.3)',
                      transform: 'scale(1.1)',
                    },
                  }}
                >
                  <Share sx={{ fontSize: 18 }} />
                </IconButton>
              </Tooltip>
            </Box>

            {/* Bottom info */}
            <Box>
              {/* Rating */}
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1 }}>
                <Rating
                  value={movie.avg_rating || 0}
                  precision={0.5}
                  readOnly
                  size="small"
                  icon={<Star sx={{ color: '#fbbf24' }} />}
                  emptyIcon={<StarBorder sx={{ color: 'rgba(255, 255, 255, 0.5)' }} />}
                />
                <Typography
                  variant="body2"
                  sx={{
                    color: 'white',
                    fontWeight: 600,
                    fontSize: '0.8rem',
                  }}
                >
                  {movie.avg_rating ? movie.avg_rating.toFixed(1) : 'No rating'}
                </Typography>
              </Box>

              {/* Plot preview */}
              {movie.plot && (
                <Typography
                  variant="body2"
                  sx={{
                    color: 'rgba(255, 255, 255, 0.9)',
                    fontSize: '0.75rem',
                    lineHeight: 1.3,
                    display: '-webkit-box',
                    WebkitLineClamp: 3,
                    WebkitBoxOrient: 'vertical',
                    overflow: 'hidden',
                  }}
                >
                  {movie.plot}
                </Typography>
              )}

              {/* Quick actions */}
              <Box sx={{ display: 'flex', gap: 1, mt: 2 }}>
                <Button
                  component={Link}
                  to={`/movies/${movie.id}`}
                  size="small"
                  startIcon={<PlayArrow />}
                  sx={{
                    background: 'linear-gradient(135deg, #a855f7 0%, #ec4899 100%)',
                    color: 'white',
                    borderRadius: '0.5rem',
                    fontWeight: 600,
                    fontSize: '0.75rem',
                    minWidth: 'auto',
                    px: 2,
                    '&:hover': {
                      background: 'linear-gradient(135deg, #9333ea 0%, #db2777 100%)',
                      transform: 'scale(1.05)',
                    },
                  }}
                >
                  Details
                </Button>
                <IconButton
                  size="small"
                  sx={{
                    background: 'rgba(255, 255, 255, 0.2)',
                    backdropFilter: 'blur(8px)',
                    color: 'white',
                    '&:hover': {
                      background: 'rgba(255, 255, 255, 0.3)',
                    },
                  }}
                >
                  <BookmarkBorder sx={{ fontSize: 18 }} />
                </IconButton>
              </Box>
            </Box>
          </Box>
        </Fade>
      </Box>

      {/* Card Content */}
      <CardContent sx={{ 
        flex: 1, 
        display: 'flex', 
        flexDirection: 'column', 
        gap: 1.5,
        p: 2,
        position: 'relative',
        zIndex: 2,
      }}>
        {/* Title and Year */}
        <Box>
          <Typography
            component={Link}
            to={`/movies/${movie.id}`}
            variant="h6"
            sx={{
              fontWeight: 700,
              fontSize: '1rem',
              lineHeight: 1.2,
              color: 'white',
              textDecoration: 'none',
              display: 'block',
              transition: 'color 0.2s ease',
              '&:hover': {
                color: '#c084fc',
              },
            }}
            title={movie.title}
          >
            {truncateTitle(movie.title)}
          </Typography>
          <Typography
            variant="body2"
            sx={{
              color: 'rgba(255, 255, 255, 0.7)',
              fontSize: '0.85rem',
            }}
          >
            {formatYear(movie.year)}
          </Typography>
        </Box>

        {/* User's rating if available */}
        {userRating && (
          <Box
            sx={{
              display: 'flex',
              alignItems: 'center',
              gap: 1,
              p: 1.5,
              background: 'rgba(168, 85, 247, 0.1)',
              border: '1px solid rgba(168, 85, 247, 0.3)',
              borderRadius: '0.75rem',
              backdropFilter: 'blur(8px)',
            }}
          >
            <Typography
              variant="caption"
              sx={{
                color: '#c084fc',
                fontWeight: 600,
                fontSize: '0.75rem',
              }}
            >
              Your rating:
            </Typography>
            <Rating
              value={userRating.rating}
              readOnly
              size="small"
              icon={<Star sx={{ color: '#fbbf24' }} />}
              emptyIcon={<StarBorder sx={{ color: 'rgba(255, 255, 255, 0.3)' }} />}
            />
          </Box>
        )}

        {/* Quick rating for authenticated users */}
        {isAuthenticated && !userRating && (
          <Box sx={{ mt: 'auto' }}>
            {!showQuickRate ? (
              <Button
                onClick={(e) => {
                  e.stopPropagation();
                  setShowQuickRate(true);
                }}
                disabled={isRating}
                fullWidth
                size="small"
                startIcon={<Star />}
                sx={{
                  background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  color: 'white',
                  borderRadius: '0.75rem',
                  fontWeight: 600,
                  py: 1,
                  transition: 'all 0.2s ease',
                  '&:hover': {
                    background: 'linear-gradient(135deg, #5a67d8 0%, #667eea 100%)',
                    transform: 'scale(1.02)',
                  },
                  '&:disabled': {
                    opacity: 0.6,
                    transform: 'none',
                  },
                }}
              >
                Quick Rate
              </Button>
            ) : (
              <Box
                onClick={(e) => e.stopPropagation()}
                sx={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 1,
                  p: 1.5,
                  background: 'rgba(255, 255, 255, 0.1)',
                  border: '1px solid rgba(255, 255, 255, 0.2)',
                  borderRadius: '0.75rem',
                  backdropFilter: 'blur(8px)',
                }}
              >
                <Typography
                  variant="caption"
                  sx={{
                    color: 'rgba(255, 255, 255, 0.8)',
                    fontWeight: 600,
                    fontSize: '0.75rem',
                  }}
                >
                  Rate:
                </Typography>
                <Rating
                  value={hoverRating || quickRating}
                  onChange={(event, newValue) => {
                    setQuickRating(newValue);
                    handleQuickRate(newValue);
                  }}
                  onChangeActive={(event, newHover) => {
                    setHoverRating(newHover);
                  }}
                  size="small"
                  icon={<Star sx={{ color: '#fbbf24' }} />}
                  emptyIcon={<StarBorder sx={{ color: 'rgba(255, 255, 255, 0.5)' }} />}
                />
                <IconButton
                  onClick={() => setShowQuickRate(false)}
                  size="small"
                  sx={{
                    color: '#f87171',
                    ml: 'auto',
                    '&:hover': {
                      background: 'rgba(248, 113, 113, 0.1)',
                    },
                  }}
                >
                  <Close sx={{ fontSize: 16 }} />
                </IconButton>
              </Box>
            )}
          </Box>
        )}

        {/* Movie metadata */}
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 0.5, mt: 'auto' }}>
          {movie.rating_count > 0 && (
            <Typography
              variant="caption"
              sx={{
                color: 'rgba(255, 255, 255, 0.6)',
                fontSize: '0.75rem',
              }}
            >
              {movie.rating_count} rating{movie.rating_count !== 1 ? 's' : ''}
            </Typography>
          )}

          {showRecommendationScore && movie.recommendation_score && (
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
              <TrendingUp sx={{ fontSize: 16, color: '#4ade80' }} />
              <Typography
                variant="caption"
                sx={{
                  color: '#4ade80',
                  fontWeight: 600,
                  fontSize: '0.75rem',
                }}
              >
                {(movie.recommendation_score * 100).toFixed(0)}% Match
              </Typography>
            </Box>
          )}
        </Box>

        {/* Genres */}
        {movie.genres && movie.genres.length > 0 && (
          <Box sx={{ display: 'flex', gap: 0.5, flexWrap: 'wrap', mt: 1 }}>
            {movie.genres.slice(0, 3).map(genre => (
              <Chip
                key={genre}
                label={genre}
                size="small"
                sx={{
                  background: 'rgba(59, 130, 246, 0.2)',
                  color: '#93c5fd',
                  border: '1px solid rgba(59, 130, 246, 0.3)',
                  fontWeight: 500,
                  fontSize: '0.7rem',
                  height: 20,
                }}
              />
            ))}
            {movie.genres.length > 3 && (
              <Typography
                variant="caption"
                sx={{
                  color: 'rgba(255, 255, 255, 0.5)',
                  fontSize: '0.7rem',
                  alignSelf: 'center',
                  fontStyle: 'italic',
                }}
              >
                +{movie.genres.length - 3} more
              </Typography>
            )}
          </Box>
        )}
      </CardContent>

      {/* Loading overlay for rating */}
      <Backdrop
        open={isRating}
        sx={{
          position: 'absolute',
          zIndex: 10,
          background: 'rgba(255, 255, 255, 0.1)',
          backdropFilter: 'blur(4px)',
          borderRadius: '1rem',
        }}
      >
        <Box
          sx={{
            display: 'flex',
            alignItems: 'center',
            gap: 1,
            color: 'white',
          }}
        >
          <CircularProgress 
            size={24} 
            sx={{ 
              color: '#a855f7',
              '& .MuiCircularProgress-circle': {
                strokeLinecap: 'round',
              },
            }} 
          />
          <Typography variant="body2" sx={{ fontWeight: 500 }}>
            Rating...
          </Typography>
        </Box>
      </Backdrop>
    </Card>
  );
};

// Demo wrapper with dark background
export default function ModernMovieCardDemo() {
  return (
    <Box
      sx={{
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #0f172a 0%, #1e1b4b 50%, #0f172a 100%)',
        padding: 4,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
      }}
    >
      <Box sx={{ width: '100%', maxWidth: 400 }}>
        <MovieCard />
      </Box>
    </Box>
  );
}
